	if err := dec.Decode(&e); err != nil {
		s.rejected.WithLabelValues("bad_json").Inc()
		http.Error(w, "bad json", http.StatusBadRequest)
		return
	}
	if err := s.validateEvent(&e); err != nil {
		s.rejected.WithLabelValues("validation").Inc()
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	userID, _ := s.sanitizeLabelValue(e.UserID)
	reqID, _ := s.sanitizeLabelValue(e.RequestID)
	method, _ := s.sanitizeLabelValue(strings.ToUpper(e.Method))
	path, _ := s.sanitizeLabelValue(e.Path)
	status := strconv.Itoa(e.Status)

	baseKeys := []string{"user_id", "request_id", "method", "path", "status"}
	baseVals := []string{userID, reqID, method, path, status}

	keys, vals := s.mergeDynamicLabels(baseKeys, baseVals, e.Labels)

