	s.mu.Unlock()

	s.reqTotal.With(collectorLabels).Inc()
	s.reqLatency.With(collectorLabels).Observe(clampFloat(e.DurationMS) / 1000.0)
	s.reqSizeIn.With(collectorLabels).Observe(clampFloat(e.BytesIn))
	s.reqSizeOut.With(collectorLabels).Observe(clampFloat(e.BytesOut))

